15: /// Parse a single grep / rg result line into its components.
16: /// Tries the structured forms in order: column-form
17: /// (`path:line:col:body`), match (`path:line:body`), file-only
18: /// (`path:body`), single-file `<line>:<body>` (no path prefix),
19: /// context with `-` separators, then bare-path heading.
20: pub(super) fn parse_grep_line<'a>(raw: &'a str) -> Option<GrepLine<'a>> {
21:     // Try `:` separator first (most common).
22:     if let Some(parsed) = parse_grep_with_sep(raw, ':', false) {
23:         return Some(parsed);
24:     }
25:     // Then `-` for context lines.
26:     if let Some(parsed) = parse_grep_with_sep(raw, '-', true) {
27:         return Some(parsed);
28:     }
29:     // No path prefix: `grep -n pat single-file` emits `<lineno>:<body>`.
30:     // Also rg `--no-filename`. Detect by leading digits + `:`.
31:     if let Some(parsed) = parse_grep_no_path(raw, ':', false) {
32:         return Some(parsed);
33:     }
34:     // No-path context (grep `-A`/`-B`/`-C` against single file):
35:     // `<lineno>-<body>`.
36:     if let Some(parsed) = parse_grep_no_path(raw, '-', true) {
37:         return Some(parsed);
38:     }
39:     // Fall back to bare-path detection: a line that *looks like* a
40:     // file path (has slash or extension) and contains no `:` or
41:     // `-` markers is probably a heading.
42:     let trimmed = raw.trim();
43:     if !trimmed.is_empty()
44:         && (trimmed.contains('/') || std::path::Path::new(trimmed).extension().is_some())
45:         && !trimmed.contains(':')
46:     {
47:         return Some(GrepLine::HeadingPath(trimmed));
48:     }
49:     None
50: }
