52: /// Parse the path-less `<lineno><sep><body>` form. Used by single-
53: /// file grep invocations where the filename isn't repeated on each
54: /// line. Returns `Match` with `path = ""` so the renderer skips
55: /// the path span entirely.
56: pub(super) fn parse_grep_no_path<'a>(
57:     raw: &'a str,
58:     sep: char,
59:     is_context: bool,
60: ) -> Option<GrepLine<'a>> {
61:     let bytes = raw.as_bytes();
62:     if bytes.is_empty() || !bytes[0].is_ascii_digit() {
63:         return None;
64:     }
65:     let mut j = 0;
66:     while j < bytes.len() && bytes[j].is_ascii_digit() {
67:         j += 1;
68:     }
69:     // After the digit run, expect the separator. Reject if the
70:     // digit run is the whole line (just a number, no body).
71:     if j >= bytes.len() || bytes[j] != sep as u8 {
72:         return None;
73:     }
74:     let lineno = &raw[..j];
75:     let body = &raw[j + 1..];
76:     // Reasonable line numbers are 1..=10M. Anything wildly larger
77:     // is probably a different format (a hex offset, a hash) we
78:     // shouldn't false-match.
79:     if lineno.parse::<u32>().is_err() {
80:         return None;
81:     }
82:     Some(GrepLine::Match {
83:         path: "",
84:         lineno: Some(lineno),
85:         col: None,
86:         body,
87:         is_context,
88:     })
89: }
