91: /// Look for `path<sep>lineno<sep>[col<sep>]body` in `raw`.
92: /// Returns None if the structure doesn't match — caller falls
93: /// through to the next separator or the heading-path fallback.
94: pub(super) fn parse_grep_with_sep<'a>(
95:     raw: &'a str,
96:     sep: char,
97:     is_context: bool,
98: ) -> Option<GrepLine<'a>> {
99:     // Walk the string finding `<sep><digits><sep>` — that
100:     // anchors the "this is a (path, lineno) prefix" claim. Without
101:     // the digit-bracketed pattern, a path like
102:     // `src/foo:bar.rs:10:hi` would mis-parse.
103:     let bytes = raw.as_bytes();
104:     let sep_b = sep as u8;
105:     let mut i = 0;
106:     let mut path_end: Option<usize> = None;
107:     while i < bytes.len() {
108:         if bytes[i] == sep_b {
109:             // Tentative path ends at i. After i+1, we want digits
110:             // then another sep.
111:             let after = i + 1;
112:             let mut j = after;
113:             while j < bytes.len() && bytes[j].is_ascii_digit() {
114:                 j += 1;
115:             }
116:             if j > after && j < bytes.len() && bytes[j] == sep_b {
117:                 path_end = Some(i);
118:                 break;
119:             }
120:         }
121:         i += 1;
122:     }
123:     let p_end = path_end?;
124:     let path = &raw[..p_end];
125:     if path.is_empty() {
126:         return None;
127:     }
128:     let after_path = p_end + 1;
129:     let mut lineno_end = after_path;
130:     while lineno_end < bytes.len() && bytes[lineno_end].is_ascii_digit() {
131:         lineno_end += 1;
132:     }
133:     if lineno_end == after_path || lineno_end >= bytes.len() || bytes[lineno_end] != sep_b {
134:         return None;
135:     }
136:     let lineno = &raw[after_path..lineno_end];
137:     let after_lineno = lineno_end + 1;
138:     // Optional column: another `<digits><sep>` block.
139:     let mut col: Option<&str> = None;
140:     let body_start;
141:     let mut col_end = after_lineno;
142:     while col_end < bytes.len() && bytes[col_end].is_ascii_digit() {
143:         col_end += 1;
144:     }
145:     if col_end > after_lineno && col_end < bytes.len() && bytes[col_end] == sep_b {
146:         col = Some(&raw[after_lineno..col_end]);
147:         body_start = col_end + 1;
148:     } else {
149:         body_start = after_lineno;
150:     }
151:     let body = &raw[body_start..];
152:     Some(GrepLine::Match {
153:         path,
154:         lineno: Some(lineno),
155:         col,
156:         body,
157:         is_context,
158:     })
159: }
