212: /// Walk the original command and return the first positional that
213: /// looks like a file/directory the user grep'd against. Used by
214: /// `render_grep_output_skip` to surface a heading line when grep
215: /// emitted path-less `<lineno>:<body>` rows (single-file mode), so
216: /// the user can see *which* file is being searched.
217: ///
218: /// Heuristic: skip the verb (`grep`/`rg`/`ack`/`ag`), skip flags
219: /// (`-X`, `--long`), skip the value of flag pairs that take an
220: /// argument (`-e PAT`, `-f FILE`, `--type rust`), skip what looks
221: /// like the regex pattern (the first un-quoted positional). The
222: /// next positional is the target file/path. Quote-aware so a
223: /// pattern like `"foo("` doesn't get mistaken for a path. Returns
224: /// the path with surrounding quotes stripped.
225: pub(super) fn grep_target_file(cmd: &str) -> Option<String> {
226:     let toks = quote_aware_tokens(cmd);
227:     let mut it = toks.into_iter();
228:     let verb = it.next()?;
229:     if !matches!(verb.as_str(), "grep" | "rg" | "ack" | "ag" | "ripgrep") {
230:         return None;
231:     }
232:     // Flags whose value lives in the *next* token. Skip both.
233:     const VALUE_FLAGS: &[&str] = &[
234:         "-e",
235:         "-f",
236:         "-A",
237:         "-B",
238:         "-C",
239:         "-m",
240:         "--max-count",
241:         "--type",
242:         "-t",
243:         "--type-not",
244:         "-T",
245:         "--color",
246:         "--colour",
247:         "-g",
248:         "--glob",
249:         "--iglob",
250:         "--include",
251:         "--exclude",
252:         "--exclude-dir",
253:         "--threads",
254:         "-j",
255:     ];
256:     // `-e PAT` and `-f FILE` (regex source file) supply the pattern
257:     // via a flag value rather than a positional. When we see one of
258:     // those we absorb the value AND mark seen_pattern so the next
259:     // positional is treated as the target file.
260:     const PATTERN_FLAGS: &[&str] = &["-e", "--regexp", "-f", "--file"];
261:     let mut seen_pattern = false;
262:     while let Some(tok) = it.next() {
263:         if tok.starts_with("--") {
264:             let key = tok.split('=').next().unwrap_or(&tok);
265:             if PATTERN_FLAGS.contains(&key) {
266:                 if !tok.contains('=') {
267:                     let _ = it.next();
268:                 }
269:                 seen_pattern = true;
270:                 continue;
271:             }
272:             if !tok.contains('=') && VALUE_FLAGS.contains(&tok.as_str()) {
273:                 let _ = it.next();
274:             }
275:             continue;
276:         }
277:         if tok.starts_with('-') && tok.len() > 1 && !tok.chars().all(|c| c == '-') {
278:             if PATTERN_FLAGS.contains(&tok.as_str()) {
279:                 let _ = it.next();
280:                 seen_pattern = true;
281:                 continue;
282:             }
283:             if VALUE_FLAGS.contains(&tok.as_str()) {
284:                 let _ = it.next();
285:             }
286:             continue;
287:         }
288:         if !seen_pattern {
289:             seen_pattern = true;
290:             continue;
291:         }
292:         // First positional after the pattern → target.
293:         let unquoted = tok
294:             .strip_prefix('\'')
295:             .and_then(|s| s.strip_suffix('\''))
296:             .or_else(|| tok.strip_prefix('"').and_then(|s| s.strip_suffix('"')))
297:             .map(|s| s.to_string())
298:             .unwrap_or(tok);
299:         return Some(unquoted);
300:     }
301:     None
302: }]

