230:     for raw in stdout.lines() {
231:         total += 1;
232:         if lines.len() >= max_lines {
233:             continue;
234:         }
235:         // `ls -l` long format: `<perms> <links> <user> <group> <size> <date> <name>`
236:         // — first char is a file-type indicator (`-`, `d`, `l`, etc.).
237:         let is_ls_long = raw
238:             .chars()
239:             .next()
240:             .map(|c| matches!(c, '-' | 'd' | 'l' | 'c' | 'b' | 'p' | 's'))
241:             .unwrap_or(false)
242:             && raw.split_whitespace().count() >= 7;
243:         if is_ls_long {
244:             let cols: Vec<&str> = raw.splitn(9, char::is_whitespace).collect();
245:             // Re-split smarter: we want file mode, ..., name (which
246:             // may contain spaces in `ls -lQ` etc.).
247:             let parts: Vec<&str> = raw.split_whitespace().collect();
248:             if parts.len() >= 8 {
249:                 let perms = parts[0];
250:                 // Find the size column (5th non-empty token after links)
251:                 let name_start = parts[..parts.len() - 1]
252:                     .iter()
253:                     .map(|s| s.len())
254:                     .sum::<usize>()
255:                     + parts.len()
256:                     - 2; // approximation
257:                 let name = parts.last().copied().unwrap_or("");
258:                 let _ = name_start;
259:                 let _ = cols;
260:                 let mut spans: Vec<Span<'static>> = Vec::new();
261:                 spans.push(Span::styled(
262:                     perms.to_owned(),
263:                     Style::default().fg(t.text_muted),
264:                 ));
265:                 spans.push(Span::raw(" "));
266:                 // Middle columns rendered muted as one block.
267:                 let middle = parts[1..parts.len() - 1].join(" ");
268:                 spans.push(Span::styled(middle, Style::default().fg(t.text_muted)));
269:                 spans.push(Span::raw(" "));
270:                 spans.push(Span::styled(
271:                     name.to_owned(),
272:                     Style::default().fg(path_color(name, t)),
273:                 ));
274:                 lines.push(Line::from(spans));
275:                 continue;
276:             }
277:         }
278:         // Simple path-per-line: tint by extension.
279:         let trimmed = raw.trim_end();
280:         if trimmed.is_empty() {
281:             lines.push(Line::from(""));
282:         } else {
283:             lines.push(Line::from(Span::styled(
284:                 raw.to_owned(),
285:                 Style::default().fg(path_color(trimmed, t)),
286:             )));
287:         }
288:     }
289:     if total > max_lines {
290:         lines.push(Line::from(Span::styled(
291:             format!(
292:                 "… {} more lines · click or press o to expand",
293:                 total - max_lines
294:             ),
295:             Style::default()
296:                 .fg(t.text_muted)
297:                 .add_modifier(Modifier::ITALIC),
298:         )));
299:     }
300:     if !stderr.is_empty() {
301:         if !lines.is_empty() {
302:             lines.push(Line::from(""));
303:         }
304:         for sl in stderr.lines() {
305:             lines.push(Line::from(Span::styled(
306:                 sanitize_terminal_text(sl),
307:                 Style::default().fg(t.error),
308:             )));
309:         }
310:     }
311:     lines
312: }
