314: /// Produce `git diff` / `git show` output as colored unified diff
315: /// lines. Each line gets a per-prefix color: `+` green, `-` red, `@@`
316: /// cyan, file headers bold, index/`diff --git` lines muted.
317: /// Parse the substring after `diff --git ` into `(a_path, b_path)`.
318: /// Handles quoted paths (Git emits these when `core.quotePath` triggers
319: /// on non-ASCII or whitespace) but skips C-string unescaping — only the
320: /// extension is needed downstream for syntect.
321: fn parse_diff_git_paths(rest: &str) -> Option<(String, String)> {
322:     let trimmed = rest.trim();
323:     let (a_quoted, after_a) = if let Some(stripped) = trimmed.strip_prefix('"') {
324:         let end = stripped.find('"')?;
325:         (&stripped[..end], stripped[end + 1..].trim_start())
326:     } else {
327:         let end = trimmed.find(' ')?;
328:         (&trimmed[..end], trimmed[end + 1..].trim_start())
329:     };
330:     let b_quoted = if let Some(stripped) = after_a.strip_prefix('"') {
331:         let end = stripped.find('"')?;
332:         &stripped[..end]
333:     } else {
334:         after_a.split_whitespace().next()?
335:     };
336:     let strip_prefix = |p: &str| -> String {
337:         p.strip_prefix("a/")
338:             .or_else(|| p.strip_prefix("b/"))
339:             .unwrap_or(p)
340:             .to_owned()
341:     };
342:     Some((strip_prefix(a_quoted), strip_prefix(b_quoted)))
343: }
