345: pub(super) fn produce_git_diff_output_lines(
346:     stdout: &str,
347:     stderr: &str,
348:     exit_code: Option<i32>,
349:     content_w: usize,
350:     t: Theme,
351:     expanded: bool,
352: ) -> Vec<Line<'static>> {
353:     let max_lines = if expanded { 1000usize } else { 200usize };
354:     let mut lines: Vec<Line<'static>> = Vec::new();
355:     if let Some(code) = exit_code {
356:         // git diff exits 1 when there are differences (with --exit-code).
357:         // 0 = no diffs, 1 = diffs found, >1 = real error.
358:         if code > 1 {
359:             lines.push(Line::from(Span::styled(
360:                 format!("[exit {code}]"),
361:                 Style::default().fg(t.error),
362:             )));
363:         }
364:     }
365: 
366:     // Pre-pass: strip ANSI from every line so prefix matching, hunk
367:     // batching, and syntect highlighting all see the original source
368:     // text. `git diff --color=always` (and `git -c color.ui=always`)
369:     // wraps every line in SGR escapes (`\u{1b}[1m…\u{1b}[m`); without
370:     // this strip the prefix checks below never fire and the raw
371:     // escapes leak into the rendered Paragraph.
372:     let cleaned: Vec<String> = stdout.lines().map(sanitize_terminal_text).collect();
373:     let total = cleaned.len();
374: 
375:     if looks_like_difftastic_output(stdout) {
376:         return produce_difftastic_output_lines(
377:             &cleaned, stderr, exit_code, content_w, t, expanded,
378:         );
379:     }
380: 
381:     let mut current_lang: Option<String> = None;
382:     let mut hunk: Vec<(DiffLineKind, String)> = Vec::new();
383: 
384:     let flush = |hunk: &mut Vec<(DiffLineKind, String)>,
385:                  lang: &Option<String>,
386:                  lines: &mut Vec<Line<'static>>,
387:                  max_lines: usize,
388:                  t: Theme| {
389:         if hunk.is_empty() {
390:             return;
391:         }
392:         let body: String = hunk
393:             .iter()
394:             .map(|(_, content)| content.as_str())
395:             .collect::<Vec<_>>()
396:             .join("\n");
397:         // `wrap_w=0` → 1:1 line mapping from `highlight_code_raw`
398:         // (no wrapping inside syntect). On pathological inputs syntect
399:         // can still drift by a line; the per-line fallback below
400:         // re-highlights individually rather than dropping all color.
401:         let highlighted = lang.as_deref().and_then(|l| {
402:             let hl = markdown::highlight_code_raw(l, &body, 0, &t);
403:             (hl.len() == hunk.len()).then_some(hl)
404:         });
405:         for (idx, (kind, content)) in hunk.drain(..).enumerate() {
406:             if lines.len() >= max_lines {
407:                 break;
408:             }
409:             let (bg_color, fg_color, sigil) = match kind {
410:                 DiffLineKind::Added => (t.code_bg, t.success, '+'),
411:                 DiffLineKind::Removed => (t.code_bg, t.error, '-'),
412:                 DiffLineKind::Context => (t.bg, t.text_secondary, ' '),
413:             };
414:             let mut spans: Vec<Span<'static>> = vec![Span::styled(
415:                 format!("{sigil} "),
416:                 Style::default().fg(fg_color).bg(bg_color),
417:             )];
418:             let extra_mod = matches!(kind, DiffLineKind::Removed).then_some(Modifier::DIM);
419:             let push_hl_spans = |target: &mut Vec<Span<'static>>, hl_spans: &[Span<'static>]| {
420:                 for sp in hl_spans {
421:                     let mut style = sp.style;
422:                     style.bg = Some(bg_color);
423:                     if let Some(m) = extra_mod {
424:                         style = style.add_modifier(m);
425:                     }
426:                     target.push(Span::styled(sp.content.clone().into_owned(), style));
427:                 }
428:             };
429:             match highlighted.as_ref().and_then(|h| h.get(idx)) {
430:                 Some(hl) => {
431:                     push_hl_spans(&mut spans, &hl.spans);
432:                 }
433:                 None => {
434:                     // Resilient fallback: re-run syntect on just this
435:                     // line so a hunk-level mismatch doesn't strip all
436:                     // color from every row in the block.
437:                     let single = lang.as_deref().and_then(|l| {
438:                         markdown::highlight_code_raw(l, &content, 0, &t)
439:                             .into_iter()]

