3: pub(super) fn produce_highlighted_with_line_numbers_lines(
4:     lang: &str,
5:     text: &str,
6:     content_w: usize,
7:     t: Theme,
8:     expanded: bool,
9:     diag_lines: &std::collections::HashMap<usize, crate::diagnostics::Severity>,
10: ) -> Vec<Line<'static>> {
11:     let (line_numbers, code) = split_line_numbers(text);
12:     let code_ref = code.as_deref().unwrap_or(text);
13: 
14:     let gutter_width = line_numbers
15:         .as_ref()
16:         .map(|nums| nums.iter().map(|n| n.len()).max().unwrap_or(0))
17:         .unwrap_or(0);
18: 
19:     // When we have any diagnostics for this file, reserve one column
20:     // for the severity glyph between the line number and separator
21:     // (` 12 ✘ │ `). When no diagnostics, the gutter stays at the
22:     // existing width so unaffected reads don't shift.
23:     let has_diags = !diag_lines.is_empty();
24:     let glyph_w: usize = if has_diags { 2 } else { 0 };
25:     let gutter_cols = if gutter_width > 0 {
26:         gutter_width + 3 + glyph_w
27:     } else {
28:         2
29:     };
30:     let code_w = content_w.saturating_sub(gutter_cols).max(10);
31: 
32:     let max_lines = if expanded { 500usize } else { 80usize };
33:     let highlighted = markdown::highlight_code_raw(lang, code_ref, code_w, &t);
34:     let total = highlighted.len();
35:     let truncated = total > max_lines;
36:     let take_n = total.min(max_lines);
37: 
38:     let gutter_style = Style::default().fg(t.text_muted);
39:     let separator_style = Style::default().fg(t.border);
40: 
41:     let mut lines: Vec<Line<'static>> = highlighted
42:         .into_iter()
43:         .take(take_n)
44:         .enumerate()
45:         .map(|(i, mut hl_line)| {
46:             let mut spans = if let Some(nums) = &line_numbers {
47:                 let num_str = nums.get(i).map(|s| s.as_str()).unwrap_or("");
48:                 let mut spans_init = vec![Span::styled(
49:                     format!("{:>width$}", num_str, width = gutter_width),
50:                     gutter_style,
51:                 )];
52:                 if has_diags {
53:                     let lineno: usize = num_str.parse().unwrap_or(0);
54:                     let (glyph, color) = match diag_lines.get(&lineno) {
55:                         Some(crate::diagnostics::Severity::Error) => ("✘", t.error),
56:                         Some(crate::diagnostics::Severity::Warning) => ("⚠", t.warning),
57:                         Some(crate::diagnostics::Severity::Info) => ("ℹ", t.accent),
58:                         Some(crate::diagnostics::Severity::Hint) => ("★", t.text_secondary),
59:                         None => (" ", t.text_muted),
60:                     };
61:                     spans_init.push(Span::styled(
62:                         format!(" {glyph}"),
63:                         Style::default().fg(color).add_modifier(Modifier::BOLD),
64:                     ));
65:                 }
66:                 spans_init.push(Span::styled(" │ ", separator_style));
67:                 spans_init
68:             } else {
69:                 vec![Span::styled("│ ", separator_style)]
70:             };
71:             spans.append(&mut hl_line.spans);
72:             Line::from(spans)
73:         })
74:         .collect();
75: 
76:     if truncated {
77:         lines.push(Line::from(Span::styled(
78:             format!(
79:                 "… {} more lines · click or press o to expand",
80:                 total - take_n
81:             ),
82:             Style::default()
83:                 .fg(t.text_muted)
84:                 .add_modifier(Modifier::ITALIC),
85:         )));
86:     }
87:     lines
88: }
