90: pub(super) fn split_line_numbers(text: &str) -> (Option<Vec<String>>, Option<String>) {
91:     let lines: Vec<&str> = text.lines().collect();
92:     if lines.is_empty() {
93:         return (None, None);
94:     }
95:     let mut numbers = Vec::with_capacity(lines.len());
96:     let mut code_lines = Vec::with_capacity(lines.len());
97: 
98:     for line in &lines {
99:         if line.is_empty() {
100:             numbers.push(String::new());
101:             code_lines.push("");
102:             continue;
103:         }
104:         match line.find(": ") {
105:             Some(pos) if line[..pos].bytes().all(|b| b.is_ascii_digit()) => {
106:                 numbers.push(line[..pos].to_string());
107:                 code_lines.push(&line[pos + 2..]);
108:             }
109:             _ => return (None, None),
110:         }
111:     }
112:     (Some(numbers), Some(code_lines.join("\n")))
113: }
