115: pub(super) fn infer_lang_from_tool(tool: &ToolCall) -> Option<String> {
116:     let path: &str = match &tool.input {
117:         ToolInput::Read { file_path, .. } => file_path.as_str(),
118:         ToolInput::Edit { file_path, .. } => file_path.as_str(),
119:         ToolInput::Write { file_path, .. } => file_path.as_str(),
120:         // Bash: when the user runs `cat path/file.ext`, `head -N file`,
121:         // or `tail file`, the stdout *is* the file content. Sniff
122:         // the command for one of those shapes and pull out the path
123:         // so the output gets the same language treatment as a Read.
124:         // Mirrors v126's bash → file-content highlighting heuristic.
125:         ToolInput::Bash { command, .. } => {
126:             return infer_lang_from_bash(command);
127:         }
128:         _ => return None,
129:     };
130:     lang_from_path(path)
131: }
