145: /// Quote-aware tokenizer. Splits `cmd` on whitespace except inside
146: /// matched single- or double-quoted segments, which are emitted as
147: /// a single token. `awk '{print $1}' file` → `["awk", "'{print $1}'",
148: /// "file"]`. Backslashes escape the next char outside quotes. We
149: /// keep the quote characters in the returned token so callers can
150: /// still detect "this token was quoted" by its leading char.
151: pub(super) fn quote_aware_tokens(cmd: &str) -> Vec<String> {
152:     let mut out: Vec<String> = Vec::new();
153:     let mut cur = String::new();
154:     let mut chars = cmd.chars().peekable();
155:     let mut quote: Option<char> = None;
156:     while let Some(c) = chars.next() {
157:         match (quote, c) {
158:             (None, ws) if ws.is_whitespace() => {
159:                 if !cur.is_empty() {
160:                     out.push(std::mem::take(&mut cur));
161:                 }
162:             }
163:             (None, '\'') | (None, '"') => {
164:                 cur.push(c);
165:                 quote = Some(c);
166:             }
167:             (Some(q), c2) if c2 == q => {
168:                 cur.push(c2);
169:                 quote = None;
170:             }
171:             (None, '\\') => {
172:                 cur.push('\\');
173:                 if let Some(n) = chars.next() {
174:                     cur.push(n);
175:                 }
176:             }
177:             _ => cur.push(c),
178:         }
179:     }
180:     if !cur.is_empty() {
181:         out.push(cur);
182:     }
183:     out
184: }
185: 
186: /// Replace the contents of every single- and double-quoted segment
187: /// in `cmd` with spaces, preserving the surrounding quotes and the
188: /// original length. Used to make the dangerous-meta-character checks
189: /// (`$`, `;`, etc.) quote-aware: `sed -n '1,$p' file` is a perfectly
190: /// safe sed call but the `$` lives inside `'…'` so we shouldn't
191: /// reject it. Without this, the canonical sed/awk idiom defeats the
192: /// language-inference path and the file falls back to plain rendering.
193: pub(super) fn redact_quoted(cmd: &str) -> String {
194:     let mut out = String::with_capacity(cmd.len());
195:     let mut chars = cmd.chars().peekable();
196:     let mut quote: Option<char> = None;
197:     while let Some(c) = chars.next() {
198:         match (quote, c) {
199:             (None, '\'') | (None, '"') => {
200:                 out.push(c);
201:                 quote = Some(c);
202:             }
203:             (Some(q), c2) if c2 == q => {
204:                 out.push(c2);
205:                 quote = None;
206:             }
207:             (Some(_), _) => out.push(' '),
208:             (None, '\\') => {
209:                 // Skip the next char so an escaped quote doesn't
210:                 // start a fake quoted segment.
211:                 out.push('\\');
212:                 if let Some(n) = chars.next() {
213:                     out.push(n);
214:                 }
215:             }
216:             (None, _) => out.push(c),
217:         }
218:     }
219:     out
220: }
221: 
222: /// Recognise `cat <file>` / `head <file>` / `tail <file>` commands
223: /// (with or without flags) and return the inferred language. Skips
224: /// when the command does anything fancier (pipes, redirects, multi-
225: /// file cats) — those need their own treatment, and over-applying
226: /// syntax highlighting to e.g. piped output breaks readability.
227: pub(super) fn infer_lang_from_bash(command: &str) -> Option<String> {
228:     // Pipeline + chain aware. `cmd1 || cmd2` takes cmd1; `cmd | less`
229:     // takes cmd; `cd X && cat README.md` takes the LAST segment
230:     // (the cat). Same logic as `classify_bash_cmd` so the two
231:     // dispatch paths agree.
232:     let primary_alt = command
233:         .split("||")
234:         .next()
235:         .unwrap_or(command)
236:         .split('|')
237:         .next()
238:         .unwrap_or(command);
239:     let primary = primary_alt
240:         .split("&&")
241:         .filter(|s| !s.trim().is_empty())
242:         .last()
243:         .unwrap_or(primary_alt);
244:     let trimmed = primary.trim();
245: 
246:     // Reject command-substitution / backticks / lone `&` / `;` —
247:     // those still indicate the cat is wrapped in something funky
248:     // and the file-path sniff would lie. `&&` was already split
249:     // out so any `&` here is the lone-background form. Check
250:     // *outside* quoted strings so `sed -n '1,$p' file.md` (the
251:     // canonical "print all lines" idiom) doesn't get rejected for
252:     // its quoted `$`.
253:     let probe = redact_quoted(trimmed);
254:     if probe.contains('$') || probe.contains('`') || probe.contains('&') || probe.contains(';') {
255:         return None;
256:     }
257:     // Strip stderr-redirect tokens like `2>/dev/null` or `2>&1`
258:     // so the file-path sniff works on the cat side. We tokenize
259:     // *quote-aware* so awk's `'{print $1}'` (which contains a
260:     // whitespace) stays a single token instead of fragmenting and
261:     // confusing the file-path sniff.
262:     let toks: Vec<String> = quote_aware_tokens(trimmed)
263:         .into_iter()
264:         .filter(|t| !t.starts_with("2>") && !t.starts_with('>'))
265:         .collect();
266:     let mut it = toks.iter().map(|s| s.as_str());
267:     let verb = it.next()?;
268:     if !matches!(
269:         verb,
270:         "cat"
271:             | "head"
272:             | "tail"
273:             | "bat"
274:             | "less"
275:             | "more"
276:             | "sed"
277:             | "awk"
278:             | "perl"
279:             | "jq"
280:             | "yq"
281:             | "python"
282:             | "python3"
283:             | "node"
284:     ) {
285:         return None;
286:     }
287: 
288:     // jq/yq always output JSON/YAML
289:     if matches!(verb, "jq") {
290:         return Some("json".to_string());
291:     }
292:     if matches!(verb, "yq") {
293:         return Some("yaml".to_string());
294:     }
295:     // python/node inline scripts — highlight as that language
296:     if matches!(verb, "python" | "python3") {
297:         return Some("python".to_string());
298:     }
299:     if matches!(verb, "node") {
300:         return Some("javascript".to_string());
301:     }
302:     // Pick the file-path argument. For most verbs the first
303:     // non-flag/non-numeric token is the file. For sed/awk/perl the
304:     // FIRST positional is the script (`'1,$p'`, `'{print}'`, ...);
305:     // the file is the next positional. Detect a script positional
306:     // by its leading quote character (the tokenizer kept quotes
307:     // because we split on whitespace, not via a real shell parser).
308:     let script_verb = matches!(verb, "sed" | "awk" | "perl");
309:     let mut seen_positional = false;
310:     let mut file: Option<&str> = None;
311:     for arg in it {
312:         if arg.starts_with('-') {
313:             continue;
314:         }
315:         if arg.parse::<i64>().is_ok() {
316:             continue;
317:         }
318:         // For sed/awk/perl: skip the first positional iff it looks
319:         // like a script (starts with a quote). A bare path with no
320:         // surrounding quotes still wins, so `awk file.txt` works
321:         // (degenerate but harmless).
322:         if script_verb && !seen_positional && (arg.starts_with('\'') || arg.starts_with('"')) {
323:             seen_positional = true;
324:             continue;
325:         }
326:         file = Some(arg);
327:         break;
328:     }
329:     let path = file?;
330:     lang_from_path(path)
331: }
