333: /// Heuristic: does this text look like markdown content? Used when
334: /// the file path didn't tell us (e.g. `.sisyphus`, `README` with no
335: /// extension, hidden dotfile that happens to be MD). Counts the
336: /// most distinctive markers in the first 2KB so a long file's
337: /// detection is cheap.
338: pub(super) fn looks_like_markdown(text: &str) -> bool {
339:     let prefix: &str = if text.len() > 2048 {
340:         // Char-boundary safe — `text` is user file content that
341:         // commonly carries UTF-8 (em-dashes, smart quotes, non-Latin
342:         // scripts), and a raw byte slice panics when a multi-byte
343:         // glyph straddles byte 2048. Same family of bug as
344:         // slop_guard.rs:114.
345:         let cap = text.floor_char_boundary(2048);
346:         &text[..cap]
347:     } else {
348:         text
349:     };
350:     let mut score = 0;
