28: /// Difftastic's side-by-side display is commonly installed as Git's external
29: /// diff. Its output is not unified diff text: it starts sections with headers
30: /// like `src/main.rs --- 1/3 --- Rust` or
31: /// `src/main.rs --- Text (exceeded DFT_GRAPH_LIMIT)` and then emits aligned
32: /// old/new columns. Treat this as preformatted diff output rather than code.
33: pub(super) fn looks_like_difftastic_output(text: &str) -> bool {
34:     for raw in text.lines().take(40) {
35:         let line = sanitize_terminal_text(raw);
36:         let trimmed = line.trim();
37:         if trimmed.starts_with("--- ") || trimmed.starts_with("+++ ") {
38:             continue;
39:         }
40:         if trimmed.contains("exceeded DFT_") {
41:             return true;
42:         }
43:         let Some((path, rest)) = trimmed.split_once(" --- ") else {
44:             continue;
45:         };
46:         if path.trim().is_empty() || rest.trim().is_empty() {
47:             continue;
48:         }
49:         if rest.contains(" --- ") {
50:             return true;
51:         }
52:         let token = rest.split_whitespace().next().unwrap_or("");
53:         if token.chars().next().is_some_and(|c| c.is_ascii_uppercase()) {
54:             return true;
55:         }
56:     }
57:     false
58: }]

